const tags = $input.all()[0].json.tags || [];
const brandMap = {
  'digitalravagers': 'brand-01',
  'employee school': 'brand-02',
  'blooming chatbots': 'brand-03',
  'shields from scams': 'brand-04',
  'georgeofthisjungle': 'brand-05',
  'house of mayas': 'brand-06',
  'agniqo': 'brand-07',
  'creative grooves': 'brand-08',
  'THEP the human evolution project': 'brand-09',
  'Artificial George Intelligence-AGI': 'brand-09'
};
const lowerTags = tags.map(t => t.toLowerCase());
let brand = 'unrouted';
for (const [key, val] of Object.entries(brandMap)) {
  if (lowerTags.some(t => t.includes(key.toLowerCase()))) { brand = val; break; }
}
return [{ ...$input.all()[0].json, brand_id: brand }];
